package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonNull;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a JsonNull element to pass to constructor
        JsonNull jsonNull = JsonNull.INSTANCE;
        jsonTreeReader = new JsonTreeReader(jsonNull);

        // Use reflection to set stack and stackSize for testing nextNull
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stack = new Object[32];
        stack[0] = JsonNull.INSTANCE;
        stackField.set(jsonTreeReader, stack);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        // Initialize pathIndices array
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = new int[32];
        pathIndicesField.set(jsonTreeReader, pathIndices);
    }

    @Test
    public void testNextNull_stackSizeGreaterThanZero_incrementsPathIndices() throws Exception {
        // Spy on jsonTreeReader to verify expect and popStack calls
        JsonTreeReader spyReader = Mockito.spy(jsonTreeReader);

        // Stub expect to do nothing (simulate expected token)
        doNothing().when(spyReader).expect(JsonToken.NULL);

        // Stub popStack to remove top of stack and decrement stackSize
        doAnswer(invocation -> {
            Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
            stackSizeField.setAccessible(true);
            int currentSize = stackSizeField.getInt(spyReader);
            stackSizeField.setInt(spyReader, currentSize - 1);

            Field stackField = JsonTreeReader.class.getDeclaredField("stack");
            stackField.setAccessible(true);
            Object[] stack = (Object[]) stackField.get(spyReader);
            stack[currentSize - 1] = null;

            return JsonNull.INSTANCE;
        }).when(spyReader).popStack();

        // Before calling nextNull, pathIndices[stackSize-1] should be 0
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = (int[]) pathIndicesField.get(spyReader);
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        int stackSizeBefore = stackSizeField.getInt(spyReader);
        int indexBefore = pathIndices[stackSizeBefore - 1];
        assertEquals(0, indexBefore);

        // Call nextNull
        spyReader.nextNull();

        // After call, stackSize should be decremented by 1
        int stackSizeAfter = stackSizeField.getInt(spyReader);
        assertEquals(stackSizeBefore - 1, stackSizeAfter);

        // Since stackSizeAfter > 0, pathIndices[stackSizeAfter - 1] should be incremented by 1
        if (stackSizeAfter > 0) {
            assertEquals(1, pathIndices[stackSizeAfter - 1]);
        }
    }

    @Test
    public void testNextNull_stackSizeZero_doesNotIncrementPathIndices() throws Exception {
        // Spy on jsonTreeReader to verify expect and popStack calls
        JsonTreeReader spyReader = Mockito.spy(jsonTreeReader);

        // Stub expect to do nothing (simulate expected token)
        doNothing().when(spyReader).expect(JsonToken.NULL);

        // Stub popStack to remove top of stack and decrement stackSize to zero
        doAnswer(invocation -> {
            Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
            stackSizeField.setAccessible(true);
            int currentSize = stackSizeField.getInt(spyReader);
            stackSizeField.setInt(spyReader, 0);

            Field stackField = JsonTreeReader.class.getDeclaredField("stack");
            stackField.setAccessible(true);
            Object[] stack = (Object[]) stackField.get(spyReader);
            for (int i = 0; i < currentSize; i++) {
                stack[i] = null;
            }

            return JsonNull.INSTANCE;
        }).when(spyReader).popStack();

        // Set stackSize to 1 before call
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(spyReader, 1);

        // Initialize pathIndices with zeros
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = new int[32];
        pathIndicesField.set(spyReader, pathIndices);

        // Call nextNull
        spyReader.nextNull();

        // After call, stackSize should be zero
        int stackSizeAfter = stackSizeField.getInt(spyReader);
        assertEquals(0, stackSizeAfter);

        // pathIndices array should remain unchanged (all zeros)
        for (int i = 0; i < pathIndices.length; i++) {
            assertEquals(0, pathIndices[i]);
        }
    }

    @Test
    public void testNextNull_expectThrowsIOException() throws Exception {
        // Spy on jsonTreeReader to verify expect throwing IOException
        JsonTreeReader spyReader = Mockito.spy(jsonTreeReader);

        doThrow(new IOException("Expected token not found")).when(spyReader).expect(JsonToken.NULL);

        IOException thrown = assertThrows(IOException.class, spyReader::nextNull);
        assertEquals("Expected token not found", thrown.getMessage());
    }
}
